class Solution:
    def incremovableSubarrayCount(self, nums: List[int]) -> int:
        n = len(nums)
        count = 0
        for i in range(n):
            for j in range(i, n):
                sub = nums[:i] + nums[j+1:]
                is_increasing = True
                for k in range(1, len(sub)):
                    if sub[k] <= sub[k-1]:
                        is_increasing = False
                        break
                if is_increasing:
                    count += 1
        return count
